          </span>

          <blockquote className="max-w-[28ch] self-center">
            <p className="v3-founder-quote font-serif text-[#F4F4F2]">
              {QUOTE.body}
            </p>

            <footer className="mt-10 flex flex-wrap items-baseline gap-x-4 gap-y-1 border-t border-[#1F242B] pt-6">
