        {/* --------------------------------------------------------------- */}
        <dl className="mt-20 grid grid-cols-2 gap-x-6 gap-y-6 border-t border-[#1F242B] pt-8 font-mono text-[10px] uppercase tracking-[0.28em] sm:grid-cols-4 md:mt-24">
          <div>
